use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type QuorumDatum {
  voters: List<ByteArray>,
  quorum_pct: Int,
}

pub type QuorumRedeemer {
  Approve
  Reject
}

fn count_present_voters(
  voters: List<ByteArray>,
  signatories: List<ByteArray>,
) -> Int {
  list.count(voters, fn(voter) { list.has(signatories, voter) })
}

fn total_voters(voters: List<ByteArray>) -> Int {
  list.count(voters, fn(_voter) { True })
}

validator quorum_vote {
  spend(
    datum: Option<QuorumDatum>,
    redeemer: QuorumRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(qd) -> {
        when redeemer is {
          Reject -> False
          Approve -> {
            let total = total_voters(qd.voters)
            if total == 0 {
              False
            } else {
              let present =
                count_present_voters(qd.voters, self.extra_signatories)
              let present_pct = present * 100 / total
              present_pct >= qd.quorum_pct
            }
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}

