use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

pub type WeightedDatum {
  signers: List<ByteArray>,
  weights: List<Int>,
  min_weight: Int,
}

pub type Redeemer {
  Spend
}

fn zip_with_weight(
  signers: List<ByteArray>,
  weights: List<Int>,
) -> List<(ByteArray, Int)> {
  when signers is {
    [] -> []
    [s, ..rest_s] ->
      when weights is {
        [] -> []
        [w, ..rest_w] -> [(s, w), ..zip_with_weight(rest_s, rest_w)]
      }
  }
}

fn compute_total_weight(
  pairs: List<(ByteArray, Int)>,
  signatories: List<ByteArray>,
) -> Int {
  list.foldl(
    pairs,
    0,
    fn(pair, acc) {
      let (signer, weight) = pair
      if list.has(signatories, signer) {
        acc + weight
      } else {
        acc
      }
    },
  )
}

validator weighted_multisig {
  spend(
    datum: Option<WeightedDatum>,
    _redeemer: Redeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let pairs = zip_with_weight(d.signers, d.weights)
        let total_weight =
          compute_total_weight(pairs, self.extra_signatories)
        total_weight >= d.min_weight
      }
    }
  }

  else(_) {
    fail
  }
}

