use aiken/collection/list
use cardano/assets
use cardano/transaction.{Input, OutputReference, Transaction}

pub type MultiSigDatum {
  holders: List<ByteArray>,
  threshold: Int,
  nft_policy: ByteArray,
}

pub type MultiSigRedeemer {
  Spend
}

fn count_signers(
  signatories: List<ByteArray>,
  holders: List<ByteArray>,
) -> Int {
  list.count(signatories, fn(sig) { list.has(holders, sig) })
}

fn has_nft_policy_in_inputs(
  inputs: List<Input>,
  nft_policy: ByteArray,
) -> Bool {
  list.any(
    inputs,
    fn(input) {
      let value = input.output.value
      let policies = assets.policies(value)
      list.has(policies, nft_policy)
    },
  )
}

validator nft_multisig {
  spend(
    datum: Option<MultiSigDatum>,
    _redeemer: MultiSigRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let present =
          count_signers(self.extra_signatories, d.holders)
        let threshold_met = present >= d.threshold
        let nft_present =
          has_nft_policy_in_inputs(self.inputs, d.nft_policy)
        threshold_met && nft_present
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type UpgradeDatum {
  governors: List<ByteArray>,
  supermajority: Int,
  current_version: Int,
}

pub type UpgradeRedeemer {
  new_version: Int,
}

fn count_governor_signatures(
  governors: List<ByteArray>,
  signatories: List<ByteArray>,
) -> Int {
  list.count(governors, fn(gov) { list.has(signatories, gov) })
}

fn total_governors(governors: List<ByteArray>) -> Int {
  list.length(governors)
}

fn supermajority_satisfied(
  governors: List<ByteArray>,
  signatories: List<ByteArray>,
  supermajority: Int,
) -> Bool {
  let present = count_governor_signatures(governors, signatories)
  let total = total_governors(governors)
  present * 100 >= total * supermajority
}

validator protocol_upgrade {
  spend(
    datum: Option<UpgradeDatum>,
    redeemer: UpgradeRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let new_version_valid = redeemer.new_version > d.current_version
        let governors_valid = list.length(d.governors) > 0
        let supermajority_valid =
          d.supermajority > 0 && d.supermajority <= 100
        let signatures_valid =
          supermajority_satisfied(
            d.governors,
            self.extra_signatories,
            d.supermajority,
          )
        new_version_valid && governors_valid && supermajority_valid && signatures_valid
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type EscrowDatum {
  buyer: ByteArray,
  seller: ByteArray,
  arbitrators: List<ByteArray>,
  threshold: Int,
}

pub type EscrowRedeemer {
  MutualRelease
  ArbitrationRelease
}

fn mutual_release(datum: EscrowDatum, tx: Transaction) -> Bool {
  let buyer_signed =
    list.any(tx.extra_signatories, fn(sig) { sig == datum.buyer })
  let seller_signed =
    list.any(tx.extra_signatories, fn(sig) { sig == datum.seller })
  buyer_signed && seller_signed
}

fn arbitration_release(datum: EscrowDatum, tx: Transaction) -> Bool {
  let approvals =
    list.count(
      tx.extra_signatories,
      fn(sig) { list.has(datum.arbitrators, sig) },
    )
  approvals >= datum.threshold
}

validator arbitration_escrow {
  spend(
    datum: Option<EscrowDatum>,
    redeemer: EscrowRedeemer,
    _output_reference: OutputReference,
    tx: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          MutualRelease -> mutual_release(d, tx)
          ArbitrationRelease -> arbitration_release(d, tx)
        }
    }
  }

  else(_) {
    fail
  }
}

