use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type WalletDatum {
  cold_keys: List<ByteArray>,
  hot_keys: List<ByteArray>,
  cold_threshold: Int,
  hot_threshold: Int,
  amount_limit: Int,
}

pub type WalletRedeemer {
  Hot
  Cold
}

fn get_spending_amount(self: Transaction, own_ref: OutputReference) -> Int {
  let own_input =
    list.filter(
      self.inputs,
      fn(input) { input.output_reference == own_ref },
    )
  when own_input is {
    [input, ..] -> assets.lovelace_of(input.output.value)
    [] -> 0
  }
}

validator cold_hot_wallet {
  spend(
    datum: Option<WalletDatum>,
    redeemer: WalletRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(wallet) -> {
        let spending_amount = get_spending_amount(self, own_ref)
        when redeemer is {
          Hot -> {
            let is_small_amount = spending_amount <= wallet.amount_limit
            let hot_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(wallet.hot_keys, sig) },
              )
            let hot_approved = hot_present >= wallet.hot_threshold
            is_small_amount && hot_approved
          }
          Cold -> {
            let cold_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(wallet.cold_keys, sig) },
              )
            cold_present >= wallet.cold_threshold
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}

