pub type TieredDatum {
  signers: List<ByteArray>,
  low_threshold: Int,
  high_threshold: Int,
  limit: Int,
}

pub type TieredRedeemer {
  amount: Int,
}

fn count_signers(
  required: List<ByteArray>,
  extra_signatories: List<ByteArray>,
) -> Int {
  list.count(extra_signatories, fn(sig) { list.has(required, sig) })
}

validator tiered_auth {
  spend(
    datum: Option<TieredDatum>,
    redeemer: TieredRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let present = count_signers(d.signers, self.extra_signatories)
        let required_threshold =
          if redeemer.amount < d.limit {
            d.low_threshold
          } else {
            d.high_threshold
          }
        present >= required_threshold
      }
    }
  }

  else(_) {
    fail
  }
}

