    datum: Option<ApprovalDatum>,
    _redeemer: ApprovalRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        if d.stage == 0 {
          let present =
            list.count(
              self.extra_signatories,
              fn(sig) { list.has(d.approvers_stage1, sig) },
