use aiken/collection/list
use aiken/interval.{Finite}
use cardano/transaction.{Transaction, OutputReference}

pub type Datum {
  required_signers: List<ByteArray>,
  threshold: Int,
  unlock_time: Int,
}

pub type Redeemer {
  Spend
}

validator timed_multisig {
  spend(
    datum: Option<Datum>,
    _redeemer: Redeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let time_ok =
          when self.validity_range.lower_bound.bound_type is {
            Finite(t) -> t >= d.unlock_time
            _ -> False
          }

        let present =
          list.count(
            self.extra_signatories,
            fn(sig) { list.has(d.required_signers, sig) },
          )

        let sigs_ok = present >= d.threshold

        time_ok && sigs_ok
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use aiken/interval.{Finite}
use cardano/transaction.{Transaction, OutputReference}

pub type Datum {
  signers: List<ByteArray>,
  threshold: Int,
  emergency_key: ByteArray,
  deadline: Int,
}

pub type Redeemer {
  Normal
  Emergency
}

validator emergency_multisig {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          Normal -> {
            let is_before_deadline =
              interval.is_entirely_before(self.validity_range, d.deadline)
            let present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.signers, sig) },
              )
            is_before_deadline && present >= d.threshold
          }
          Emergency -> {
            let is_after_deadline =
              interval.is_entirely_after(self.validity_range, d.deadline)
            let emergency_signed =
              list.has(self.extra_signatories, d.emergency_key)
            is_after_deadline && emergency_signed
          }
        }
    }
  }

  else(_) {
    False
  }
}

