            fn(sig) { list.has(d.signers, sig) },
          )
        let after_decay =
          when self.validity_range.lower_bound.bound_type is {
            Finite(t) -> t >= d.decay_time
            _ -> False
          }
        let before_decay =
          when self.validity_range.upper_bound.bound_type is {
            Finite(t) -> t < d.decay_time
            _ -> False
          }
        if before_decay {
          present >= d.initial_threshold
        } else if after_decay {
          present >= d.reduced_threshold
        } else {
          False
        }
      }
    }
  }

  else(_) {
    False
  }
}

