pub type WeightedDatum {
  signers: List<ByteArray>,
  weights: List<Int>,
  min_weight: Int,
}

fn zip_with_weight(
  signers: List<ByteArray>,
  weights: List<Int>,
  extra_signatories: List<ByteArray>,
) -> Int {
  when signers is {
    [] -> 0
    [signer, ..rest_signers] ->
      when weights is {
        [] -> 0
        [weight, ..rest_weights] -> {
          let contribution =
            if list.has(extra_signatories, signer) {
              weight
            } else {
              0
            }
          contribution + zip_with_weight(
            rest_signers,
            rest_weights,
            extra_signatories,
          )
        }
      }
  }
}

validator weighted_multisig {
  spend(
    datum: Option<WeightedDatum>,
    _redeemer: Data,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let total_weight =
          zip_with_weight(d.signers, d.weights, self.extra_signatories)
        total_weight >= d.min_weight
      }
    }
  }

  else(_) {
    fail
  }
}

