  hot_threshold: Int,
  amount_limit: Int,
}

pub type WalletRedeemer {
  HotSpend
  ColdSpend
}

fn total_spent(tx: Transaction, datum: WalletDatum) -> Int {
  let script_inputs =
    list.filter(
      tx.inputs,
      fn(input) {
        when input.output.value |> assets.lovelace_of is {
          _ -> True
        }
      },
    )
  list.foldl(
    script_inputs,
    0,
    fn(input, acc) { acc + assets.lovelace_of(input.output.value) },
  )
}

fn max_output_to_new_address(tx: Transaction) -> Int {
  list.foldl(
    tx.outputs,
    0,
    fn(output, acc) {
      let v = assets.lovelace_of(output.value)
      if v > acc {
        v
      } else {
        acc
      }
    },
  )
}

validator cold_hot_wallet {
  spend(
    datum: Option<WalletDatum>,
    redeemer: WalletRedeemer,
    _input: OutputReference,
