  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          HotSpend -> {
            let hot_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.hot_keys, sig) },
              )
            let spending_amount = max_output_to_new_address(self)
            hot_present >= d.hot_threshold && spending_amount <= d.amount_limit
          }
          ColdSpend -> {
            let cold_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.cold_keys, sig) },
              )
            cold_present >= d.cold_threshold
          }
        }
    }
  }

  else(_) {
