            Finite(t) -> t >= d.decay_time
            _ -> False
          }
        if after_decay {
          present >= d.reduced_threshold
        } else {
          let before_decay =
            when self.validity_range.upper_bound.bound_type is {
              Finite(t) -> t < d.decay_time
              _ -> False
