    list.count(tx.extra_signatories, fn(sig) { list.has(guardians, sig) })
  present >= threshold
}

fn after_delay(tx: Transaction, delay: Int) -> Bool {
  when tx.validity_range.lower_bound.bound_type is {
    Finite(t) -> t >= delay
    _ -> False
  }
}

validator recovery_wallet {
  spend(
    datum: Option<RecoveryDatum>,
    redeemer: RecoveryRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          OwnerSpend -> owner_signed(self, d.owner)
          GuardianRecover { new_owner } -> {
            let guardians_ok =
              guardian_threshold_met(self, d.guardians, d.guardian_threshold)
            let delay_ok = after_delay(self, d.recovery_delay)
            let new_owner_signed = list.has(self.extra_signatories, new_owner)
            guardians_ok && delay_ok && new_owner_signed
          }
        }
    }
  }

  else(_) {
    False
  }
}

