fn is_before_expiry(tx: Transaction, expiry: Int) -> Bool {
  when tx.validity_range.upper_bound.bound_type is {
    Finite(t) -> t < expiry
    _ -> False
  }
}

fn is_after_expiry(tx: Transaction, expiry: Int) -> Bool {
  when tx.validity_range.lower_bound.bound_type is {
    Finite(t) -> t >= expiry
    _ -> False
  }
}

fn multisig_valid(
  tx: Transaction,
  signers: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(tx.extra_signatories, fn(sig) { list.has(signers, sig) })
  present >= threshold
}

fn fallback_signed(tx: Transaction, fallback: ByteArray) -> Bool {
  list.has(tx.extra_signatories, fallback)
}

validator expiring_multisig {
  spend(
    datum: Option<ExpiryDatum>,
    redeemer: ExpiryRedeemer,
    _output_reference: OutputReference,
