  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          MultisigSpend ->
            is_before_expiry(self, d.expiry) && multisig_valid(
              self,
              d.signers,
              d.threshold,
            )
          FallbackSpend ->
            is_after_expiry(self, d.expiry) && fallback_signed(
              self,
              d.fallback,
            )
        }
    }
  }

  else(_) {
    fail
  }
}

