pub type ContractTerms {
  client: ByteArray,
  contractor: ByteArray,
  mediators: List<ByteArray>,
  required_mediators: Int,
  require_unanimous_parties: Bool,
}

pub type ResolutionRedeemer {
  MutualAgreement
  MediatorDecision
}

fn parties_agreed(terms: ContractTerms, tx: Transaction) -> Bool {
  let client_signed =
    list.any(tx.extra_signatories, fn(sig) { sig == terms.client })
  let contractor_signed =
    list.any(tx.extra_signatories, fn(sig) { sig == terms.contractor })
  if terms.require_unanimous_parties {
    client_signed && contractor_signed
  } else {
    client_signed || contractor_signed
  }
}

fn majority_mediators_approved(terms: ContractTerms, tx: Transaction) -> Bool {
  let total_mediators = list.length(terms.mediators)
  let majority_threshold = total_mediators / 2 + 1
  let effective_threshold =
    if terms.required_mediators >= majority_threshold {
      terms.required_mediators
    } else {
      majority_threshold
    }
  let present =
    list.count(
      tx.extra_signatories,
      fn(sig) { list.has(terms.mediators, sig) },
    )
  present >= effective_threshold
}

validator dispute_resolution_vault {
  spend(
    datum: Option<ContractTerms>,
    redeemer: ResolutionRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(terms) ->
        when redeemer is {
          MutualAgreement -> parties_agreed(terms, self)
          MediatorDecision -> majority_mediators_approved(terms, self)
        }
    }
  }

  else(_) {
    fail
  }
}

