pub type RoleApprovalDatum {
  approvers: List<ByteArray>,
  vote_weights: List<Int>,
  quorum: Int,
  bonus_approver: ByteArray,
}

pub type ApprovalRedeemer {
  Approve
}

fn zip_approvers(
  approvers: List<ByteArray>,
  weights: List<Int>,
) -> List<(ByteArray, Int)> {
  when approvers is {
    [] -> []
    [a, ..rest_a] ->
      when weights is {
        [] -> []
        [w, ..rest_w] -> [(a, w), ..zip_approvers(rest_a, rest_w)]
      }
  }
}

fn sum_present_weights(
  pairs: List<(ByteArray, Int)>,
  signatories: List<ByteArray>,
) -> Int {
  list.foldl(
    pairs,
    0,
    fn(pair, acc) {
      let (approver, weight) = pair
      if list.has(signatories, approver) {
        acc + weight
      } else {
        acc
      }
    },
  )
}

validator role_weighted_approval {
  spend(
    datum: Option<RoleApprovalDatum>,
    _redeemer: ApprovalRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let pairs = zip_approvers(d.approvers, d.vote_weights)
        let base_weight = sum_present_weights(pairs, self.extra_signatories)
        let bonus =
          if list.has(self.extra_signatories, d.bonus_approver) {
            10
          } else {
            0
          }
        let final_score = base_weight + bonus
        final_score >= d.quorum
      }
    }
  }

  else(_) {
    fail
  }
}

