}

fn threshold_satisfied(
  members: List<ByteArray>,
  signatories: List<ByteArray>,
  approval_threshold: Int,
) -> Bool {
  let signed = count_member_signatures(members, signatories)
  let total = list.length(members)
  signed * 100 >= total * approval_threshold
