        let has_members = list.length(d.members) > 0
        let valid_threshold =
          d.approval_threshold >= 1 && d.approval_threshold <= 100
        let enough_signatures =
          threshold_satisfied(
            d.members,
            self.extra_signatories,
            d.approval_threshold,
          )
        not_yet_executed && proposal_matches && has_members && valid_threshold && enough_signatures
      }
