fn count_member_signers(
  signatories: List<ByteArray>,
  members: List<ByteArray>,
) -> Int {
  list.count(signatories, fn(sig) { list.has(members, sig) })
}

fn majority_threshold(total: Int) -> Int {
  total / 2 + 1
}

fn has_governance_token_in_inputs(
  inputs: List<Input>,
  governance_policy: ByteArray,
) -> Bool {
  list.any(
    inputs,
    fn(input) {
      let value = input.output.value
      let policies = assets.policies(value)
      list.has(policies, governance_policy)
    },
  )
}

validator token_council_vote {
  spend(
    datum: Option<CouncilDatum>,
    _redeemer: CouncilRedeemer,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let total_members = list.length(d.members)
        let signed_count = count_member_signers(self.extra_signatories, d.members)
        let majority = majority_threshold(total_members)
        let effective_threshold =
          if majority > d.quorum {
            majority
          } else {
            d.quorum
          }
        let threshold_met = signed_count >= effective_threshold
        let governance_present =
          has_governance_token_in_inputs(self.inputs, d.governance_policy)
        threshold_met && governance_present
      }
    }
  }

  else(_) {
    fail
  }
}

