  GuardianRecovery
}

validator timelocked_council {
  spend(
    datum: Option<CouncilDatum>,
    redeemer: CouncilRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          CouncilVote -> {
            let before_expiry =
              interval.is_entirely_before(self.validity_range, d.expiry)
            let signers_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(d.members, sig) },
              )
            before_expiry && signers_present >= d.quorum
          }
          GuardianRecovery -> {
            let after_expiry =
              interval.is_entirely_after(self.validity_range, d.expiry)
            let guardian_signed =
              list.has(self.extra_signatories, d.guardian)
            after_expiry && guardian_signed
          }
        }
    }
  }

  else(_) {
    False
  }
}

