pub type ApprovalPolicy {
  members: List<ByteArray>,
  voting_power: List<Int>,
  quorum_threshold: Int,
  required_majority: Int,
}

fn compute_total_power(
  members: List<ByteArray>,
  voting_power: List<Int>,
  extra_signatories: List<ByteArray>,
) -> Int {
  when members is {
    [] -> 0
    [member, ..rest_members] ->
      when voting_power is {
        [] -> 0
        [power, ..rest_power] -> {
          let contribution =
            if list.has(extra_signatories, member) {
              power
            } else {
              0
            }
          contribution + compute_total_power(
            rest_members,
            rest_power,
            extra_signatories,
          )
        }
      }
  }
}

fn count_present_members(
  members: List<ByteArray>,
  extra_signatories: List<ByteArray>,
) -> Int {
  list.count(members, fn(member) { list.has(extra_signatories, member) })
}

validator quorum_weighted_approval {
  spend(
    datum: Option<ApprovalPolicy>,
    _redeemer: Data,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let present_count =
          count_present_members(d.members, self.extra_signatories)
        let total_power =
          compute_total_power(d.members, d.voting_power, self.extra_signatories)
        present_count >= d.quorum_threshold && total_power > d.required_majority
      }
    }
  }

  else(_) {
    fail
  }
}

