  Execute
}

validator timelocked_multisig {
  spend(
    datum: Option<GovernanceDatum>,
    _action: Action,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let present =
          list.count(
            self.extra_signatories,
            fn(sig) { list.has(d.members, sig) },
          )
        let is_locked =
          when self.validity_range.upper_bound.bound_type is {
            Finite(t) -> t < d.lock_until
            _ -> False
          }
        let is_unlocked =
          when self.validity_range.lower_bound.bound_type is {
            Finite(t) -> t >= d.lock_until
            _ -> False
          }
        if is_locked {
          present >= d.super_quorum
        } else if is_unlocked {
          present >= d.quorum
        } else {
          False
        }
      }
    }
  }

  else(_) {
    False
  }
}

