  list.count(members, fn(member) { list.has(signatories, member) })
}

fn veto_threshold_satisfied(
  members: List<ByteArray>,
  signatories: List<ByteArray>,
  threshold_percent: Int,
) -> Bool {
  let present = count_council_signatures(members, signatories)
  let total = list.length(members)
  present * 100 > total * threshold_percent
}

validator council_veto {
  spend(
    datum: Option<VetoDatum>,
    redeemer: VetoRedeemer,
    _output_reference: OutputReference,
