      None -> False
      Some(d) -> {
        let proposal_valid = d.proposal_id > 0
        let target_matches = redeemer.target_proposal_id == d.proposal_id
        let members_valid = list.length(d.council_members) > 0
        let threshold_valid =
          d.veto_threshold_percent > 50 && d.veto_threshold_percent <= 100
        let signatures_valid =
          veto_threshold_satisfied(
            d.council_members,
            self.extra_signatories,
            d.veto_threshold_percent,
          )
        proposal_valid && target_matches && members_valid && threshold_valid && signatures_valid
      }
    }
  }

  else(_) {
    fail
  }
}

