        let quorum_met = signed_count >= effective_quorum
        let chair_is_member = list.has(d.members, d.chairperson)
        let chair_signed = list.has(signatories, d.chairperson)
        quorum_met && chair_is_member && chair_signed
      }
    }
  }

  else(_) {
    fail
  }
}

