  Veto
}

validator consensus_gate {
  spend(
    datum: Option<ConsensusDatum>,
    redeemer: ConsensusRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        when redeemer is {
          Veto -> False
          Ratify -> {
            let total_delegates = list.length(d.delegates)
            if total_delegates == 0 {
              False
            } else {
              let present =
                list.count(
                  self.extra_signatories,
                  fn(sig) { list.has(d.delegates, sig) },
                )
              let present_pct = present * 100 / total_delegates
              let pct_ok = present_pct >= d.approval_threshold_pct
              let min_ok = present >= d.min_delegates
              pct_ok && min_ok
            }
          }
        }
      }
    }
  }

  else(_) {
    False
  }
