use cardano/transaction.{OutputReference, Transaction}

pub type CouncilDatum {
  members: List<ByteArray>,
  weights: List<Int>,
  approval_threshold: Int,
}

pub type CouncilRedeemer {
  Execute
  Veto
}

fn sum_weights(
  members: List<ByteArray>,
  weights: List<Int>,
  signatories: List<ByteArray>,
) -> Int {
  when members is {
    [] -> 0
    [member, ..rest_members] ->
      when weights is {
        [] -> 0
        [weight, ..rest_weights] ->
          if list.has(signatories, member) {
            weight + sum_weights(rest_members, rest_weights, signatories)
          } else {
            sum_weights(rest_members, rest_weights, signatories)
          }
      }
  }
}

fn total_weight(weights: List<Int>) -> Int {
  list.foldl(weights, 0, fn(w, acc) { acc + w })
}

validator weighted_council_vote {
  spend(
    datum: Option<CouncilDatum>,
    redeemer: CouncilRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(cd) -> {
        when redeemer is {
          Veto -> False
          Execute -> {
            let total = total_weight(cd.weights)
            if total == 0 {
              False
            } else {
              let weighted_sum =
                sum_weights(cd.members, cd.weights, self.extra_signatories)
              let weighted_pct = weighted_sum * 100 / total
              weighted_pct >= cd.approval_threshold
            }
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}

