  BenefactorWithdraw
  BeneficiaryClaim
}

fn benefactor_signed(tx: Transaction, benefactor: ByteArray) -> Bool {
  list.has(tx.extra_signatories, benefactor)
}

fn beneficiaries_threshold_met(
  tx: Transaction,
  beneficiaries: List<ByteArray>,
  threshold: Int,
) -> Bool {
  let present =
    list.count(tx.extra_signatories, fn(sig) { list.has(beneficiaries, sig) })
  present >= threshold
}

fn guardian_present(tx: Transaction, guardians: List<ByteArray>) -> Bool {
  list.any(tx.extra_signatories, fn(sig) { list.has(guardians, sig) })
}

fn after_maturity_date(tx: Transaction, maturity_date: Int) -> Bool {
  when tx.validity_range.lower_bound.bound_type is {
    Finite(t) -> t >= maturity_date
    _ -> False
  }
}

