  spend(
    datum: Option<TrustFundDatum>,
    redeemer: TrustFundRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          BenefactorWithdraw -> benefactor_signed(self, d.benefactor)
          BeneficiaryClaim ->
            beneficiaries_threshold_met(
              self,
              d.beneficiaries,
              d.release_threshold,
            ) && guardian_present(self, d.guardians) && after_maturity_date(
              self,
              d.maturity_date,
            )
        }
    }
  }

  else(_) {
    fail
  }
}

