        let members_valid = list.length(d.council_members) > 0
        let threshold_valid =
          d.approval_threshold >= 0 && d.approval_threshold < 100
        let signatures_valid =
          strict_majority_satisfied(
            d.council_members,
            self.extra_signatories,
            d.approval_threshold,
