          manager_sigs >= cfg.manager_quorum
        } else {
          let owner_sigs =
            list.count(
              self.extra_signatories,
              fn(sig) { list.has(cfg.owners, sig) },
            )
          owner_sigs >= cfg.owner_quorum
        }
      }
    }
  }

  else(_) {
    fail
  }
}

