fn max_single_output(tx: Transaction) -> Int {
  list.foldl(
    tx.outputs,
    0,
    fn(output, acc) {
      let v = assets.lovelace_of(output.value)
      if v > acc {
        v
      } else {
        acc
      }
    },
  )
}

