  ranks: List<Int>,
  required_score: Int,
  bonus_threshold: Int,
}

pub type Action {
  Approve
}

fn zip_approvers_ranks(
  approvers: List<ByteArray>,
  ranks: List<Int>,
) -> List<(ByteArray, Int)> {
  when approvers is {
    [] -> []
    [a, ..rest_a] ->
      when ranks is {
        [] -> []
        [r, ..rest_r] -> [(a, r), ..zip_approvers_ranks(rest_a, rest_r)]
      }
  }
}

fn compute_base_score(
  pairs: List<(ByteArray, Int)>,
  signatories: List<ByteArray>,
) -> Int {
  list.foldl(
    pairs,
    0,
    fn(pair, acc) {
      let (approver, rank) = pair
      if list.has(signatories, approver) {
        acc + rank
      } else {
        acc
      }
    },
  )
}

fn count_present_approvers(
  approvers: List<ByteArray>,
  signatories: List<ByteArray>,
) -> Int {
  list.count(approvers, fn(a) { list.has(signatories, a) })
}

validator ranked_approval {
  spend(
    datum: Option<RankedDatum>,
    _action: Action,
    _input: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let pairs = zip_approvers_ranks(d.approvers, d.ranks)
        let base_score = compute_base_score(pairs, self.extra_signatories)
        let present_count =
          count_present_approvers(d.approvers, self.extra_signatories)
        let bonus =
          if present_count >= d.bonus_threshold {
            10
          } else {
            0
          }
        let final_score = base_score + bonus
        final_score >= d.required_score
      }
    }
  }

  else(_) {
    fail
  }
}

