  approval_threshold: Int,
}

pub type CouncilAction {
  Execute
  Veto
}

fn sum_weights(weights: List<Int>) -> Int {
  list.foldl(weights, 0, fn(w, acc) { acc + w })
}

fn zip_sum_present(
  members: List<ByteArray>,
  weights: List<Int>,
  signatories: List<ByteArray>,
) -> Int {
  when members is {
    [] -> 0
    [m, ..rest_m] ->
      when weights is {
        [] -> 0
        [w, ..rest_w] -> {
          let contribution =
            if list.has(signatories, m) {
              w
            } else {
              0
            }
          contribution + zip_sum_present(rest_m, rest_w, signatories)
        }
      }
  }
}

validator weighted_council {
  spend(
    datum: Option<CouncilDatum>,
    action: CouncilAction,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(cd) -> {
        when action is {
          Veto -> False
          Execute -> {
            let total_weight = sum_weights(cd.weights)
            if total_weight == 0 {
              False
            } else {
              let present_weight =
                zip_sum_present(cd.members, cd.weights, self.extra_signatories)
              let present_pct = present_weight * 100 / total_weight
              present_pct >= cd.approval_threshold
            }
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

pub type WeightedProposal {
  participants: List<ByteArray>,
  weights: List<Int>,
  approval_threshold_pct: Int,
}

pub type ApprovalAction {
  Approve
  Deny
}

fn zip_sum_present(
  participants: List<ByteArray>,
  weights: List<Int>,
  signatories: List<ByteArray>,
) -> Int {
  when participants is {
    [] -> 0
    [p, ..rest_p] ->
      when weights is {
        [] -> 0
        [w, ..rest_w] -> {
          let contribution =
            if list.has(signatories, p) {
              w
            } else {
              0
            }
          contribution + zip_sum_present(rest_p, rest_w, signatories)
        }
      }
  }
}

fn sum_all_weights(weights: List<Int>) -> Int {
  list.foldl(weights, 0, fn(w, acc) { acc + w })
}

validator weighted_approval {
  spend(
    datum: Option<WeightedProposal>,
    redeemer: ApprovalAction,
    _output_reference: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(proposal) -> {
        when redeemer is {
          Deny -> False
          Approve -> {
            let total_weight = sum_all_weights(proposal.weights)
            if total_weight == 0 {
              False
            } else {
              let present_weight =
                zip_sum_present(
                  proposal.participants,
                  proposal.weights,
                  self.extra_signatories,
                )
              let present_pct = present_weight * 100 / total_weight
              present_pct >= proposal.approval_threshold_pct
            }
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type FundDatum {
  steward_keys: List<ByteArray>,
  guardian_keys: List<ByteArray>,
  steward_threshold: Int,
  guardian_threshold: Int,
  steward_daily_limit: Int,
}

pub type FundRedeemer {
  Steward
  Guardian
}

fn get_input_lovelace(self: Transaction, own_ref: OutputReference) -> Int {
  let matched =
    list.filter(
      self.inputs,
      fn(input) { input.output_reference == own_ref },
    )
  when matched is {
    [input, ..] -> assets.lovelace_of(input.output.value)
    [] -> 0
  }
}

validator layered_fund {
  spend(
    datum: Option<FundDatum>,
    redeemer: FundRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(fund) -> {
        let spending_amount = get_input_lovelace(self, own_ref)
        when redeemer is {
          Steward -> {
            let within_limit = spending_amount <= fund.steward_daily_limit
            let steward_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(fund.steward_keys, sig) },
              )
            let steward_approved = steward_present >= fund.steward_threshold
            within_limit && steward_approved
          }
          Guardian -> {
            let guardian_present =
              list.count(
                self.extra_signatories,
                fn(sig) { list.has(fund.guardian_keys, sig) },
              )
            guardian_present >= fund.guardian_threshold
          }
        }
      }
    }
  }

  else(_) {
    fail
  }
}
